SELECT DISTINCT u.user_name
FROM users u
JOIN bug_reports b ON u.user_id = b.resolved_by;

SELECT section_name
FROM test_sections
WHERE section_type = 'functional';

SELECT test_case_name, test_case_type
FROM test_cases
ORDER BY priority DESC;

SELECT section_name, description, section_type, parent_section_id
FROM test_sections
WHERE section_id = 0;

SELECT AVG(execution_time) AS average_execution_time
FROM test_results
WHERE status = 'Passed';

SELECT test_case_id
FROM test_case_tags
WHERE tag_name = 'Initialization';
